 91→  });
 92→
 93→  const unreadCountQuery = useQuery({
 94→    queryKey: ['notification-count', userId],
 95→    enabled: Boolean(token && userId),
 96→    queryFn: () => socialApi.getNotificationsCount(token, userId),
 97→  });
 98→
 99→  const markReadMutation = useMutation({
100→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
101→      socialApi.markNotificationRead(token, args.notifId, args.source),
102→    onSuccess: () => {
103→      queryClient.invalidateQueries({queryKey: ['notifications', userId]});
104→      queryClient.invalidateQueries({queryKey: ['notification-count', userId]});
105→    },
106→  });
107→
108→  const deleteMutation = useMutation({
109→    mutationFn: (args: {notifId: string; source: 'journal' | 'opinion'}) =>
110→      socialApi.deleteNotification(token, args.notifId, args.source),
111→    onSuccess: () => {
112→      queryClient.invalidateQueries({queryKey: ['notifications', userId]});
113→      queryClient.invalidateQueries({queryKey: ['notification-count', userId]});
114→    },
115→  });
116→
117→  const items = notificationsQuery.data?.data ?? [];
118→  const unreadCount = unreadCountQuery.data?.count ?? 0;
119→
120→  const handlePress = (item: NotificationItem) => {
121→    if (!item.read) {
122→      markReadMutation.mutate({notifId: item.id, source: getSource(item)});
123→    }
124→    if (item.journal_id) {
125→      navigation.navigate('PostDetail', {journalId: item.journal_id});
126→    }
127→  };
128→
